mapper.select:
SELECT q.id, q.question_type, SUBSTRING(q.content, 1, 100) AS content, q.difficulty, q.status,
       c.name AS course_name, q.create_time
FROM edu_question q
LEFT JOIN edu_course c ON q.course_id = c.id AND c.deleted = 0
WHERE q.deleted = 0

    AND q.question_type = #{query.questionType}


    AND q.difficulty = #{query.difficulty}


    AND q.course_id = #{query.courseId}


    AND q.status = #{query.status}

ORDER BY q.id DESC
